"""Ядро подготовки runtime приложения: каталоги, app.ini, логгер. Явно разделены boot ядра и модулей."""from __future__ import annotationsfrom pathlib import Pathfrom typing import Callablefrom src.core import AppConfigStorefrom src.core.app_path import AppPathfrom src.core.filesystem import ensure_dirfrom src.core.logger import DEBUG, SystemLogger, SystemLoggerStoreclass CoreBootstrap:    """    Регистрация и выполнение обработчиков при boot приложения.    Порядок: сначала core_boot(root), затем add_module_boot(...) для каждого модуля, затем modules_boot(paths).    """    _handlers: list[Callable[[AppPath], None]] = []    @staticmethod    def add_module_boot(fn: Callable[[AppPath], None]) -> None:        """Добавляет boot модуля: функцию, вызываемую при modules_boot. Сигнатура: fn(paths: AppPath) -> None."""        CoreBootstrap._handlers.append(fn)    @staticmethod    def core_boot(root: Path | None = None) -> AppPath:        """        Подготавливает runtime ядра: core-каталоги (projects, data, data/user, logs), app.ini, системный логгер.        Не создаёт доменные файлы модулей. Безопасна при повторном вызове.        Возвращает AppPath для передачи в modules_boot.        """        paths = AppPath.from_root(root)        ensure_dir(paths.projects_dir)        ensure_dir(paths.data_dir)        ensure_dir(paths.source_dir)        ensure_dir(paths.data_user_dir)        ensure_dir(paths.logs_dir)        ensure_dir(paths.cache_dir)        ensure_dir(paths.temp_dir)        SystemLoggerStore.set(            SystemLogger(logs_dir=paths.logs_dir, file_name="system", level=DEBUG)        )        AppConfigStore.load_or_create(paths.root)        SystemLoggerStore.set_level(AppConfigStore.get().core.log_level)        return paths    @classmethod    def modules_boot(cls, paths: AppPath) -> None:        """Вызывает зарегистрированные обработчики модулей (add_module_boot). Вызывать после core_boot."""        for fn in cls._handlers:            fn(paths)core_boot = CoreBootstrap.core_boot__all__ = ["CoreBootstrap", "core_boot"]